INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 2.1, -416.5, 130011, 100, "ヤマト", 3001100, 3001);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, 4, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 5.68, -416.5, 130011, 101, "ヤマト", 3001101, 3001);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 0.0, -416.5, 130011, 102, "ヤマト", 3001102, 3001);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 0.0, -416.5, 130211, 100, "フブキ", 3002100, 3002);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 0.0, -416.5, 130211, 101, "フブキ", 3002101, 3002);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, 5, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 8.53, -416.5, 130211, 102, "フブキ", 3002102, 3002);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 5.67, -416.5, 130211, 103, "フブキ", 3002103, 3002);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 0.0, -416.5, 130211, 104, "フブキ", 3002104, 3002);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (3, 3, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 0.0, -416.5, 130211, 300, "フブキ", 3002300, 3004);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 0.0, -416.5, 130211, 301, "フブキ", 3002400, 3005);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 2, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 4.4, -416.5, 130211, 200, "フブキ", 3003200, 3003);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, 7, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 0.0, -416.5, 130211, 201, "フブキ", 3003201, 3003);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, 1, "2024/10/31 12:00:00", "2030/01/01 14:59:59", 0.0, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 5.6, -416.5, 130211, 202, "フブキ", 3003202, 3003);
